import { useState, useEffect } from 'react';

// Standarized timeout for aria-live regions
const useSrLabel = () => {
  const [srLabelVisibility, setSrLabelVisibility] = useState(false);
  useEffect(() => {
    setTimeout(() => setSrLabelVisibility(true), 30);
  }, []);

  return srLabelVisibility;
};

export default useSrLabel;
